// =============================================================================
// WALLET MANAGER
// =============================================================================

class WalletManager {
  constructor() {
    this.wallets = new Map();
    this.providers = new Map();
  }

  /**
   * Get or create a provider for a network
   */
  getProvider(networkName = CONFIG.defaultNetwork) {
    if (this.providers.has(networkName)) {
      return this.providers.get(networkName);
    }

    const networkConfig = CONFIG.networks[networkName];
    if (!networkConfig) {
      throw new Error(`Unknown network: ${networkName}`);
    }

    const provider = new ethers.JsonRpcProvider(networkConfig.rpcUrl, {
      name: networkName,
      chainId: networkConfig.chainId,
    });

    this.providers.set(networkName, provider);
    return provider;
  }

  /**
   * Load a wallet from a private key stored in environment variables
   * The key name maps to an env var like WALLET_PRIVATE_KEY_<name>
   */
  loadWallet(walletName, networkName = CONFIG.defaultNetwork) {
    const cacheKey = `${walletName}:${networkName}`;
    if (this.wallets.has(cacheKey)) {
      return this.wallets.get(cacheKey);
    }

    const envVarName = `WALLET_PRIVATE_KEY_${walletName.toUpperCase()}`;
    const privateKey = process.env[envVarName];

    if (!privateKey) {
      throw new Error(
        `Private key not found. Set environment variable: ${envVarName}\n` +
        `Example: export ${envVarName}=0xYourPrivateKeyHere`
      );
    }

    // Validate the private key format
    if (!privateKey.match(/^0x[0-9a-fA-F]{64}$/)) {
      throw new Error(
        `Invalid private key format in ${envVarName}. ` +
        `Expected 0x-prefixed 64-character hex string.`
      );
    }

    const provider = this.getProvider(networkName);
    const wallet = new ethers.Wallet(privateKey, provider);

    this.wallets.set(cacheKey, wallet);
    console.log(`Wallet '${walletName}' loaded: ${wallet.address} on ${networkName}`);
    return wallet;
  }

  /**
   * Create a new random wallet (for testing purposes)
   */
  createRandomWallet(networkName = CONFIG.defaultNetwork) {
    const provider = this.getProvider(networkName);
    const wallet = ethers.Wallet.createRandom().connect(provider);
    console.log(`New wallet created: ${wallet.address}`);
    console.log(`IMPORTANT: Save this private key securely: ${wallet.privateKey}`);
    return wallet;
  }
}

