class TransactionService {
  constructor(walletManager) {
    this.walletManager = walletManager;
  }

  /**
   * Build transaction overrides (gas settings, nonce, etc.)
   */
  async _buildOverrides(wallet, overrides = {}) {
    const txOverrides = {};

    // Set gas parameters
    if (overrides.maxFeePerGas || CONFIG.gas.maxFeePerGas) {
      txOverrides.maxFeePerGas = ethers.parseUnits(
        String(overrides.maxFeePerGas || CONFIG.gas.maxFeePerGas),
        'gwei'
      );
    }

    if (overrides.maxPriorityFeePerGas || CONFIG.gas.maxPriorityFeePerGas) {
      txOverrides.maxPriorityFeePerGas = ethers.parseUnits(
        String(overrides.maxPriorityFeePerGas || CONFIG.gas.maxPriorityFeePerGas),
        'gwei'
      );
    }

    if (overrides.gasLimit || CONFIG.gas.gasLimit) {
      txOverrides.gasLimit = BigInt(overrides.gasLimit || CONFIG.gas.gasLimit);
    }

    if (overrides.nonce !== undefined) {
      txOverrides.nonce = overrides.nonce;
    }

    return txOverrides;
  }

  /**
   * Send ETH from one wallet to an address
   */
  async sendETH(walletName, toAddress, amountInEther, options = {}) {
    const networkName = options.network || CONFIG.defaultNetwork;
    const wallet = this.walletManager.loadWallet(walletName, networkName);

    // Validate address
    if (!ethers.isAddress(toAddress)) {
      throw new Error(`Invalid Ethereum address: ${toAddress}`);
    }

    // Parse amount
    const value = ethers.parseEther(String(amountInEther));

    // Check balance
    const balance = await wallet.provider.getBalance(wallet.address);
    if (balance < value) {
      throw new Error(
        `Insufficient balance. Have: ${ethers.formatEther(balance)} ETH, ` +
        `Need: ${amountInEther} ETH`
      );
    }

    // Build transaction
    const overrides = await this._buildOverrides(wallet, options);
    const tx = {
      to: toAddress,
      value: value,
      ...overrides,
    };

    console.log(`Sending ${amountInEther} ETH from ${wallet.address} to ${toAddress}...`);

    // Estimate gas if not provided
    if (!tx.gasLimit) {
      try {
        const estimatedGas = await wallet.estimateGas(tx);
        tx.gasLimit = (estimatedGas * 120n) / 100n; // Add 20% buffer
        console.log(`Estimated gas: ${estimatedGas}, Using: ${tx.gasLimit}`);
      } catch (error) {
        console.warn(`Gas estimation failed, using default: ${error.message}`);
        tx.gasLimit = 21000n;
      }
    }

    // Send transaction
    const txResponse = await wallet.sendTransaction(tx);
    console.log(`Transaction sent: ${txResponse.hash}`);

    // Wait for confirmation
    const receipt = await txResponse.wait(CONFIG.confirmations);
    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

    return {
      hash: txResponse.hash,
      from: wallet.address,
      to: toAddress,
      value: amountInEther,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
    };
  }

  /**
   * Send ETH to multiple recipients in sequence
   */
  async batchSendETH(walletName, recipients, options = {}) {
    const results = [];
    const networkName = options.network || CONFIG.defaultNetwork;
    const wallet = this.walletManager.loadWallet(walletName, networkName);
    let nonce = await wallet.getNonce();

    for (const { address, amount } of recipients) {
      try {
        const result = await this.sendETH(walletName, address, amount, {
          ...options,
          nonce: nonce,
        });
        results.push({ ...result, status: 'success' });
        nonce++;
      } catch (error) {
        results.push({
          to: address,
          value: amount,
          status: 'failed',
          error: error.message,
        });
      }
    }

    return results;
  }

  /**
   * Get wallet balance
   */
  async getBalance(walletName, networkName = CONFIG.defaultNetwork) {
    const wallet = this.walletManager.loadWallet(walletName, networkName);
    const balance = await wallet.provider.getBalance(wallet.address);
    return {
      address: wallet.address,
      balance: ethers.formatEther(balance),
      balanceWei: balance.toString(),
    };
  }

  /**
   * Get balance of any address
   */
  async getAddressBalance(address, networkName = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(networkName);
    if (!ethers.isAddress(address)) {
      throw new Error(`Invalid Ethereum address: ${address}`);
    }
    const balance = await provider.getBalance(address);
    return {
      address,
      balance: ethers.formatEther(balance),
      balanceWei: balance.toString(),
    };
  }
}

