// Example ERC-20 ABI (subset of functions)
const ERC20_ABI = [
  'function name() view returns (string)',
  'function symbol() view returns (string)',
  'function decimals() view returns (uint8)',
  'function totalSupply() view returns (uint256)',
  'function balanceOf(address owner) view returns (uint256)',
  'function transfer(address to, uint256 amount) returns (bool)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function transferFrom(address from, address to, uint256 amount) returns (bool)',
  'event Transfer(address indexed from, address indexed to, uint256 value)',
  'event Approval(address indexed owner, address indexed spender, uint256 value)',
];

class SmartContractService {
  constructor(walletManager) {
    this.walletManager = walletManager;
    this.contracts = new Map();
  }

  /**
   * Get a contract instance (read-only with provider, or read-write with wallet)
   */
  getContract(contractAddress, abi, walletOrProviderName, networkName = CONFIG.defaultNetwork) {
    if (!ethers.isAddress(contractAddress)) {
      throw new Error(`Invalid contract address: ${contractAddress}`);
    }

    let signerOrProvider;

    if (typeof walletOrProviderName === 'string') {
      try {
        // Try to load as wallet first
        signerOrProvider = this.walletManager.loadWallet(walletOrProviderName, networkName);
      } catch {
        // Fall back to provider only
        signerOrProvider = this.walletManager.getProvider(networkName);
      }
    } else {
      signerOrProvider = this.walletManager.getProvider(networkName);
    }

    return new ethers.Contract(contractAddress, abi, signerOrProvider);
  }

  /**
   * Get ERC-20 token information
   */
  async getTokenInfo(tokenAddress, networkName = CONFIG.defaultNetwork) {
    const contract = this.getContract(tokenAddress, ERC20_ABI, null, networkName);

    const [name, symbol, decimals, totalSupply] = await Promise.all([
      contract.name(),
      contract.symbol(),
      contract.decimals(),
      contract.totalSupply(),
    ]);

    return {
      address: tokenAddress,
      name,
      symbol,
      decimals: Number(decimals),
      totalSupply: ethers.formatUnits(totalSupply, decimals),
    };
  }

  /**
   * Get ERC-20 token balance for an address
   */
  async getTokenBalance(tokenAddress, ownerAddress, networkName = CONFIG.defaultNetwork) {
    const contract = this.getContract(tokenAddress, ERC20_ABI, null, networkName);
    const decimals = await contract.decimals();
    const balance = await contract.balanceOf(ownerAddress);

    return {
      tokenAddress,
      ownerAddress,
      balance: ethers.formatUnits(balance, decimals),
      balanceRaw: balance.toString(),
    };
  }

  /**
   * Transfer ERC-20 tokens
   */
  async transferToken(
    walletName,
    tokenAddress,
    toAddress,
    amount,
    options = {}
  ) {
    const networkName = options.network || CONFIG.defaultNetwork;
    const contract = this.getContract(tokenAddress, ERC20_ABI, walletName, networkName);

    const decimals = await contract.decimals();
    const parsedAmount = ethers.parseUnits(String(amount), decimals);

    // Check token balance
    const wallet = this.walletManager.loadWallet(walletName, networkName);
    const balance = await contract.balanceOf(wallet.address);
    if (balance < parsedAmount) {
      const symbol = await contract.symbol();
      throw new Error(
        `Insufficient ${symbol} balance. Have: ${ethers.formatUnits(balance, decimals)}, ` +
        `Need: ${amount}`
      );
    }

    console.log(`Transferring ${amount} tokens to ${toAddress}...`);

    // Build overrides
    const overrides = {};
    if (options.gasLimit) {
      overrides.gasLimit = BigInt(options.gasLimit);
    }

    // Execute transfer
    const tx = await contract.transfer(toAddress, parsedAmount, overrides);
    console.log(`Transaction sent: ${tx.hash}`);

    const receipt = await tx.wait(CONFIG.confirmations);
    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

    // Parse transfer events
    const transferEvents = receipt.logs
      .filter((log) => {
        try {
          return contract.interface.parseLog(log)?.name === 'Transfer';
        } catch {
          return false;
        }
      })
      .map((log) => {
        const parsed = contract.interface.parseLog(log);
        return {
          from: parsed.args.from,
          to: parsed.args.to,
          value: ethers.formatUnits(parsed.args.value, decimals),
        };
      });

    return {
      hash: tx.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
      transfers: transferEvents,
    };
  }

  /**
   * Approve ERC-20 token spending
   */
  async approveToken(walletName, tokenAddress, spenderAddress, amount, options = {}) {
    const networkName = options.network || CONFIG.defaultNetwork;
    const contract = this.getContract(tokenAddress, ERC20_ABI, walletName, networkName);

    const decimals = await contract.decimals();
    const parsedAmount = amount === 'max'
      ? ethers.MaxUint256
      : ethers.parseUnits(String(amount), decimals);

    console.log(`Approving ${spenderAddress} to spend ${amount} tokens...`);

    const tx = await contract.approve(spenderAddress, parsedAmount);
    console.log(`Transaction sent: ${tx.hash}`);

    const receipt = await tx.wait(CONFIG.confirmations);
    console.log(`Approval confirmed in block ${receipt.blockNumber}`);

    return {
      hash: tx.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
    };
  }

  /**
   * Interact with any smart contract - call a read function
   */
  async callContractFunction(
    contractAddress,
    abi,
    functionName,
    args = [],
    networkName = CONFIG.defaultNetwork
  ) {
    const contract = this.getContract(contractAddress, abi, null, networkName);

    if (typeof contract[functionName] !== 'function') {
      throw new Error(`Function '${functionName}' not found in contract ABI`);
    }

    const result = await contract[functionName](...args);
    return result;
  }

  /**
   * Interact with any smart contract - send a write transaction
   */
  async sendContractTransaction(
    walletName,
    contractAddress,
    abi,
    functionName,
    args = [],
    options = {}
  ) {
    const networkName = options.network || CONFIG.defaultNetwork;
    const contract = this.getContract(contractAddress, abi, walletName, networkName);

    if (typeof contract[functionName] !== 'function') {
      throw new Error(`Function '${functionName}' not found in contract ABI`);
    }

    // Build overrides
    const overrides = {};
    if (options.value) {
      overrides.value = ethers.parseEther(String(options.value));
    }
    if (options.gasLimit) {
      overrides.gasLimit = BigInt(options.gasLimit);
    }

    console.log(`Calling ${functionName} on ${contractAddress}...`);

    const tx = await contract[functionName](...args, overrides);
    console.log(`Transaction sent: ${tx.hash}`);

    const receipt = await tx.wait(CONFIG.confirmations);
    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

    // Parse all events
    const events = receipt.logs
      .map((log) => {
        try {
          return contract.interface.parseLog(log);
        } catch {
          return null;
        }
      })
      .filter(Boolean)
      .map((event) => ({
        name: event.name,
        args: Object.fromEntries(
          Object.entries(event.args).filter(([key]) => isNaN(Number(key)))
        ),
      }));

    return {
      hash: tx.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
      events,
    };
  }

  /**
   * Deploy a smart contract
   */
  async deployContract(walletName, abi, bytecode, constructorArgs = [], options = {}) {
    const networkName = options.network || CONFIG.defaultNetwork;
    const wallet = this.walletManager.loadWallet(walletName, networkName);

    const factory = new ethers.ContractFactory(abi, bytecode, wallet);

    console.log('Deploying contract...');

    const overrides = {};
    if (options.gasLimit) {
      overrides.gasLimit = BigInt(options.gasLimit);
    }
    if (options.value) {
      overrides.value = ethers.parseEther(String(options.value));
    }

    const contract = await factory.deploy(...constructorArgs, overrides);
    console.log(`Deployment transaction: ${contract.deploymentTransaction().hash}`);

    await contract.waitForDeployment();
    const address = await contract.getAddress();
    console.log(`Contract deployed at: ${address}`);

    return {
      address,
      hash: contract.deploymentTransaction().hash,
    };
  }

  /**
   * Listen for contract events
   */
  async listenForEvents(contractAddress, abi, eventName, callback, networkName = CONFIG.defaultNetwork) {
    const contract = this.getContract(contractAddress, abi, null, networkName);

    console.log(`Listening for '${eventName}' events on ${contractAddress}...`);

    contract.on(eventName, (...args) => {
      const event = args[args.length - 1]; // Last arg is the event object
      const eventArgs = args.slice(0, -1);
      callback({
        name: eventName,
        args: eventArgs,
        log: event.log,
        blockNumber: event.log.blockNumber,
        transactionHash: event.log.transactionHash,
      });
    });

    // Return a cleanup function
    return () => {
      contract.removeAllListeners(eventName);
      console.log(`Stopped listening for '${eventName}' events`);
    };
  }

  /**
   * Query past events
   */
  async queryPastEvents(
    contractAddress,
    abi,
    eventName,
    fromBlock = 0,
    toBlock = 'latest',
    networkName = CONFIG.defaultNetwork
  ) {
    const contract = this.getContract(contractAddress, abi, null, networkName);

    const filter = contract.filters[eventName]();
    const events = await contract.queryFilter(filter, fromBlock, toBlock);

    return events.map((event) => ({
      name: eventName,
      args: Object.fromEntries(
        Object.entries(event.args).filter(([key]) => isNaN(Number(key)))
      ),
      blockNumber: event.blockNumber,
      transactionHash: event.transactionHash,
    }));
  }
}

