class UtilityService {
  constructor(walletManager) {
    this.walletManager = walletManager;
  }

  /**
   * Get current gas prices
   */
  async getGasPrices(networkName = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(networkName);
    const feeData = await provider.getFeeData();

    return {
      gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : null,
      maxFeePerGas: feeData.maxFeePerGas
        ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei'
        : null,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas
        ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei'
        : null,
    };
  }

  /**
   * Get current block number
   */
  async getBlockNumber(networkName = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(networkName);
    return await provider.getBlockNumber();
  }

  /**
   * Get transaction receipt
   */
  async getTransactionReceipt(txHash, networkName = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(networkName);
    const receipt = await provider.getTransactionReceipt(txHash);

    if (!receipt) {
      return { status: 'pending', hash: txHash };
    }

    return {
      hash: receipt.hash,
      blockNumber: receipt.blockNumber,
      from: receipt.from,
      to: receipt.to,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
      logs: receipt.logs.length,
    };
  }

  /**
   * Wait for a transaction to be mined
   */
  async waitForTransaction(txHash, confirmations = CONFIG.confirmations, networkName = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(networkName);
    console.log(`Waiting for transaction ${txHash} (${confirmations} confirmations)...`);
    const receipt = await provider.waitForTransaction(txHash, confirmations);
    return this.getTransactionReceipt(txHash, networkName);
  }

  /**
   * Estimate gas for a transaction
   */
  async estimateGas(from, to, value, data, networkName = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(networkName);
    const tx = { from, to };

    if (value) tx.value = ethers.parseEther(String(value));
    if (data) tx.data = data;

    const gasEstimate = await provider.estimateGas(tx);
    const feeData = await provider.getFeeData();

    const estimatedCost = gasEstimate * (feeData.gasPrice || 0n);

    return {
      gasEstimate: gasEstimate.toString(),
      estimatedCostWei: estimatedCost.toString(),
      estimatedCostEth: ethers.formatEther(estimatedCost),
    };
  }

  /**
   * Encode function call data
   */
  encodeFunctionData(abi, functionName, args = []) {
    const iface = new ethers.Interface(abi);
    return iface.encodeFunctionData(functionName, args);
  }

  /**
   * Decode function call data
   */
  decodeFunctionData(abi, functionName, data) {
    const iface = new ethers.Interface(abi);
    return iface.decodeFunctionResult(functionName, data);
  }

  /**
   * Sign a message
   */
  async signMessage(walletName, message, networkName = CONFIG.defaultNetwork) {
    const wallet = this.walletManager.loadWallet(walletName, networkName);
    const signature = await wallet.signMessage(message);
    return {
      message,
      signature,
      signer: wallet.address,
    };
  }

  /**
   * Verify a signed message
   */
  verifyMessage(message, signature) {
    const recoveredAddress = ethers.verifyMessage(message, signature);
    return {
      message,
      signature,
      recoveredAddress,
    };
  }
}

